{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}
```

Create `UniversityCourseCatalog/Models/Instructor.cs`:
```csharp
namespace UniversityCourseCatalog.Models;

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Bio { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
}
```

Create `UniversityCourseCatalog/Models/Course.cs`:
```csharp
namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string Location { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public Department Department { get; set; } = default!;
    public int InstructorId { get; set; }
    public Instructor Instructor { get; set; } = default!;
    public bool IsFeatured { get; set; }
    public int MaxEnrollment { get; set; }
    public int CurrentEnrollment { get; set; }
}
```

Create `UniversityCourseCatalog/Models/EnrollmentRequest.cs`:
```csharp
using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Full name is required.")]
    [StringLength(100)]
    public string FullName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Za-z0-9]+$", ErrorMessage = "Student ID must contain only letters and numbers.")]
    [StringLength(20)]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }

    [StringLength(500)]
    public string? Notes { get; set; }
}
```

### 2. Create Services directory and files

Create `UniversityCourseCatalog/Services/ICatalogService.cs`:
```csharp
namespace UniversityCourseCatalog.Services;

using UniversityCourseCatalog.Models;

public interface ICatalogService
{
    List<Department> GetDepartments();
    Department? GetDepartment(int id);
    List<Course> GetCourses(string? search = null, int? departmentId = null);
    Course? GetCourse(int id);
    List<Course> GetFeaturedCourses();
    bool SubmitEnrollmentRequest(EnrollmentRequest request);
}
```

Create `UniversityCourseCatalog/Services/CatalogService.cs` with rich seed data:
- 5 departments: Computer Science (CS), Mathematics (MATH), Physics (PHYS), English (ENGL), History (HIST)
- 6+ instructors with realistic bios
- 3-4 courses per department (at least 16 total), varied credits 1-4, various schedules
- 4-5 courses marked IsFeatured
- Filtering by search (case-insensitive match on Title, Code, Description, Department.Name)
- Filtering by departmentId
- Combined filters work together
- Results sorted by Code
- SubmitEnrollmentRequest returns true

Here's the full implementation:

```csharp
