            new() { Id = 2, Name = "Dr. James Mitchell", Title = "Associate Professor", Bio = "Dr. Mitchell specializes in algorithms and computational complexity theory. A graduate of Stanford University, he has received multiple NSF grants for his work on approximation algorithms and has mentored dozens of graduate students.", Email = "j.mitchell@university.edu" },
