@page "/enroll"
@inject ICatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<section class="section">
    <div class="container container-narrow">
        <h1>Enrollment Request</h1>

        @if (submitted)
        {
            <div class="confirmation">
                <h2>✅ Enrollment Request Submitted</h2>
                <p>Thank you, <strong>@Request.FullName</strong>! Your enrollment request has been received.</p>
                <dl>
                    <dt>Student ID</dt>
                    <dd>@Request.StudentId</dd>
                    <dt>Course</dt>
                    <dd>@(courses.FirstOrDefault(c => c.Id == Request.CourseId)?.Title ?? "Unknown")</dd>
                    @if (!string.IsNullOrWhiteSpace(Request.Notes))
                    {
                        <dt>Notes</dt>
                        <dd>@Request.Notes</dd>
                    }
                </dl>
                <a href="/courses" class="btn btn-primary">Back to Catalog</a>
            </div>
        }
        else
        {
            <EditForm Model="Request" method="post" OnValidSubmit="HandleSubmit" FormName="enrollment">
                <AntiforgeryToken />
                <DataAnnotationsValidator />
                <ValidationSummary />

                <div class="form-group">
                    <label for="fullName">Full Name</label>
                    <InputText id="fullName" @bind-Value="Request.FullName" class="form-input" />
                    <ValidationMessage For="() => Request.FullName" />
                </div>

                <div class="form-group">
                    <label for="studentId">Student ID</label>
                    <InputText id="studentId" @bind-Value="Request.StudentId" class="form-input" />
                    <ValidationMessage For="() => Request.StudentId" />
                </div>

                <div class="form-group">
                    <label for="courseId">Course</label>
                    <InputSelect id="courseId" @bind-Value="Request.CourseId" class="form-select">
                        <option value="0">-- Select a course --</option>
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id">@course.Code: @course.Title</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Request.CourseId" />
                </div>

                <div class="form-group">
                    <label for="notes">Notes (optional)</label>
                    <InputTextArea id="notes" @bind-Value="Request.Notes" class="form-input form-textarea" />
                    <ValidationMessage For="() => Request.Notes" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
            </EditForm>
        }
    </div>
</section>

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Request { get; set; } = new();

    [SupplyParameterFromQuery(Name = "courseId")]
    public int? CourseId { get; set; }

    private List<Course> courses = new();
    private bool submitted;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();
        if (CourseId.HasValue && Request.CourseId == 0)
        {
            Request.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        CatalogService.SubmitEnrollmentRequest(Request);
        submitted = true;
    }
}
