            new() { Id = 17, Code = "HIST 340", Title = "The American Civil War Era", Description = "In-depth study of the causes, conduct, and consequences of the American Civil War, including slavery, abolition, military strategy, Reconstruction, and lasting impacts on American society.", Credits = 3, Schedule = "MWF 1:00–1:50 PM", Location = "Liberal Arts 220", DepartmentId = 5, InstructorId = 7, IsFeatured = false, MaxEnrollment = 35, CurrentEnrollment = 30 }
        };

        // Link navigation properties
        foreach (var course in _courses)
        {
            course.Department = _departments.First(d => d.Id == course.DepartmentId);
            course.Instructor = _instructors.First(i => i.Id == course.InstructorId);
        }
    }

    public List<Department> GetDepartments() => _departments.OrderBy(d => d.Name).ToList();

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Department.Name.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.OrderBy(c => c.Code).ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).OrderBy(c => c.Code).ToList();

    public bool SubmitEnrollmentRequest(EnrollmentRequest request) => true;
}
